import pygame
import math
import sys

# Initialize Pygame
pygame.init()
width, height = 800, 600
screen = pygame.display.set_mode((width, height))
pygame.display.set_caption("Rotating 3D Spiral")
clock = pygame.time.Clock()

# Generate 3D spiral points
def generate_spiral(num_points=200, loops=5):
    points = []
    for i in range(num_points):
        theta = 2 * math.pi * loops * i / num_points
        r = 0.5 * (1 + math.sin(theta))  # Varying radius
        z = 0.1 * theta  # Height increases with theta
        x = r * math.cos(theta)
        y = r * math.sin(theta)
        points.append((x, y, z))
    return points

# Generate spiral points
points = generate_spiral()

# Main loop
running = True
rotation_x = 0
rotation_y = 0
while running:
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            print("Window closed by user.")
            running = False

    # Update rotation angles
    rotation_x += 0.01
    rotation_y += 0.01

    # Clear screen
    screen.fill((0, 0, 0))

    # Project and draw each point
    projected_points = []
    for (x, y, z) in points:
        # Apply rotation around X-axis
        cos_x = math.cos(rotation_x)
        sin_x = math.sin(rotation_x)
        y_rot = y * cos_x - z * sin_x
        z_rot = y * sin_x + z * cos_x

        # Apply rotation around Y-axis
        cos_y = math.cos(rotation_y)
        sin_y = math.sin(rotation_y)
        x_rot = x * cos_y + z_rot * sin_y
        z_rot = -x * sin_y + z_rot * cos_y

        # Perspective projection
        factor = 200 / (z_rot + 5)  # Avoid division by zero
        x_proj = int(width / 2 + x_rot * factor)
        y_proj = int(height / 2 + y_rot * factor)
        projected_points.append((x_proj, y_proj))

    # Draw lines with varying colors
    for i in range(len(projected_points) - 1):
        start = projected_points[i]
        end = projected_points[i + 1]
        # Color gradient from blue to red
        color = (int(255 * i / len(projected_points)), 0, int(255 * (1 - i / len(projected_points))))
        pygame.draw.line(screen, color, start, end, 2)

    pygame.display.flip()
    clock.tick(60)

pygame.quit()
sys.exit()